def _cdist(d1: Tensor, d2: Tensor) -> Tensor:
    """Compute the pairwise Euclidean distance between `d1` and `d2`, similar to `torch.cdist`.

    Falls back to a manual computation on MPS devices, where `torch.cdist` is not well supported.
    """
    if not is_mps_tensor_safe(d1) and not is_mps_tensor_safe(d2):
        return torch.cdist(d1, d2)
    d1_sq = d1.pow(2).sum(dim=-1, keepdim=True)
    d2_sq = d2.pow(2).sum(dim=-1, keepdim=True)
    dm = d1_sq.repeat(1, d2.size(0)) + d2_sq.repeat(1, d1.size(0)).t() - 2.0 * d1 @ d2.t()
    return dm.clamp(min=0.0).sqrt()

